interface TechLogoProps {
  name: string;
  category?: 'frontend' | 'backend' | 'devops' | 'tools';
}

export function TechLogo({ name, category }: TechLogoProps) {
  const logo = logos[name];
  if (!logo) {
    if (category && fallbackIcons[category]) {
      return <span style={{ display: 'flex', alignItems: 'center' }}>{fallbackIcons[category]}</span>;
    }
    return null;
  }
  return <span style={{ display: 'flex', alignItems: 'center' }}>{logo}</span>;
}
